DOCKER_TAG ?= zhouzhouyi/os-contest:20260104
JUDGE_DOCKER_IMAGE ?= zhouzhouyi/os-contest:20260510
TESTSUITE_DIR ?= ../testsuits-for-oskernel
EVAL_ARCH ?= la

KERNEL_ELF_RV := os/target/riscv64gc-unknown-none-elf/release/os
KERNEL_ELF_LA := os-la/target-la/loongarch64-unknown-none/release/os

.PHONY: all kernel-rv kernel-la clean docker build_docker fmt run run-contest run-contest-la eval-write-docker

ifeq ($(EVAL_ARCH),all)
all: kernel-rv kernel-la
else ifeq ($(EVAL_ARCH),rv)
all: kernel-rv
	@rm -f kernel-la
	@echo "EVAL_ARCH=rv: generated kernel-rv only"
else ifeq ($(EVAL_ARCH),la)
all: kernel-rv kernel-la
	@echo "EVAL_ARCH=la: generated kernel-la and real kernel-rv"
else
all:
	$(error Unsupported EVAL_ARCH=$(EVAL_ARCH); use la, rv, or all)
endif

kernel-rv:
	@cd os && make build
	@rm -f kernel-rv
	@cp $(KERNEL_ELF_RV) kernel-rv
	@echo "Generated ELF kernel-rv"

kernel-la:
	@cd os-la && make build
	@rm -f kernel-la
	@cp $(KERNEL_ELF_LA) kernel-la
	@echo "Generated ELF kernel-la"

run:
	@cd os && make run

run-contest:
	@test -n "$(TEST_FS)" || \
		(echo "Usage: make run-contest TEST_FS=/path/to/fs.img [QEMU_GLOBAL_ARGS='...']" && exit 1)
	@cd os && make run-contest TEST_FS="$(abspath $(TEST_FS))" QEMU_GLOBAL_ARGS='$(QEMU_GLOBAL_ARGS)'

run-contest-la:
	@test -n "$(TEST_FS)" || \
		(echo "Usage: make run-contest-la TEST_FS=/path/to/fs.img [QEMU_GLOBAL_ARGS='...']" && exit 1)
	@cd os-la && make run-contest TEST_FS="$(abspath $(TEST_FS))" QEMU_GLOBAL_ARGS='$(QEMU_GLOBAL_ARGS)'

eval-write-docker:
	@JUDGE_IMAGE="$(JUDGE_DOCKER_IMAGE)" TESTSUITE_DIR="$(abspath $(TESTSUITE_DIR))" \
		BUILD_TARGET="$(BUILD_TARGET)" QEMU_TIMEOUT="$(QEMU_TIMEOUT)" \
		REBUILD_TESTSUITE="$(REBUILD_TESTSUITE)" \
		bash scripts/local_eval_write.sh

docker:
	docker run --rm -it -v ${PWD}:/code -w /code --name os-contest-dev $(DOCKER_TAG) bash

build_docker:
	docker build -t $(DOCKER_TAG) .

fmt:
	cd os && cargo fmt && cd ..
	cd os-la && cargo fmt && cd ..

clean:
	@cd os && make clean
	@cd os-la && make clean
	@rm -f kernel-rv kernel-la disk.img disk-la.img
	@echo "Clean completed"

//! RISC-V kernel entry point for the contest build.

#![deny(missing_docs)]
#![deny(warnings)]
#![no_std]
#![no_main]

use core::arch::global_asm;

#[macro_use]
mod console;
mod arch;
