use std::env;
use std::fs::{File, read_dir};
use std::io::{Result, Write};
use std::path::{Path, PathBuf};
use std::process::Command;

static TARGET_PATH: &str = "../user/target/riscv64gc-unknown-none-elf/release/";
static RUNTIME_LIBGCC_S: &str = "libgcc_s.so.1";

fn main() {
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-env-changed=RISCV_LIBGCC_S");
    stage_runtime_libgcc_s().unwrap();
    if matches!(env::var("EMBED_USER_APPS").as_deref(), Ok("1")) {
        println!("cargo:rerun-if-changed=../user/src/");
        println!("cargo:rerun-if-changed={TARGET_PATH}");
        insert_app_data().unwrap();
    } else {
        write_empty_app_data().unwrap();
    }
}

fn stage_runtime_libgcc_s() -> Result<()> {
    let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());
    let out_path = out_dir.join(RUNTIME_LIBGCC_S);
    if let Some(src) = find_runtime_libgcc_s() {
        println!("cargo:rerun-if-changed={}", src.display());
        std::fs::copy(src, out_path)?;
    } else {
        // 非官方本地环境可能没有交叉工具链运行库；写入空文件让内核保持可构建，
        // 真正暴露虚拟 libgcc_s 时会再次检查长度，避免提供无效 ELF。
        std::fs::write(out_path, [])?;
    }
    Ok(())
}

fn find_runtime_libgcc_s() -> Option<PathBuf> {
    env::var_os("RISCV_LIBGCC_S")
        .map(PathBuf::from)
        .filter(|path| path.is_file())
        .or_else(find_runtime_libgcc_s_from_compiler)
        .or_else(|| find_runtime_libgcc_s_from_known_paths())
}

fn find_runtime_libgcc_s_from_compiler() -> Option<PathBuf> {
    let output = Command::new("riscv64-linux-gnu-gcc")
        .arg("-print-file-name=libgcc_s.so.1")
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    let path = String::from_utf8(output.stdout).ok()?;
    let path = PathBuf::from(path.trim());
    path.is_file().then_some(path)
}

fn find_runtime_libgcc_s_from_known_paths() -> Option<PathBuf> {
    [
        "/usr/riscv64-linux-gnu/lib/libgcc_s.so.1",
        "/usr/lib/gcc-cross/riscv64-linux-gnu/13/../../../../riscv64-linux-gnu/lib/libgcc_s.so.1",
    ]
    .iter()
    .map(Path::new)
    .find(|path| path.is_file())
    .map(Path::to_path_buf)
}

fn write_empty_app_data() -> Result<()> {
    let mut f = File::create("src/link_app.S")?;
    writeln!(
        f,
        r#"
    .align 3
    .section .data
    .global _num_app
_num_app:
    .quad 0"#
    )
}

fn insert_app_data() -> Result<()> {
    let mut f = File::create("src/link_app.S")?;
    let mut apps: Vec<_> = read_dir("../user/src/bin")?
        .map(|dir_entry| {
            let mut name_with_ext = dir_entry.unwrap().file_name().into_string().unwrap();
            name_with_ext.drain(name_with_ext.find('.').unwrap()..name_with_ext.len());
            name_with_ext
        })
        .collect();
    apps.sort();

    writeln!(
        f,
        r#"
    .align 3
    .section .data
    .global _num_app
_num_app:
    .quad {}"#,
        apps.len()
    )?;

    for i in 0..apps.len() {
        writeln!(f, r#"    .quad app_{i}_start"#)?;
    }
    writeln!(f, r#"    .quad app_{}_end"#, apps.len() - 1)?;

    for (idx, app) in apps.iter().enumerate() {
        println!("app_{idx}: {app}");
        writeln!(
            f,
            r#"
    .section .data
    .global app_{0}_start
    .global app_{0}_end
app_{0}_start:
    .incbin "{2}{1}.bin"
app_{0}_end:"#,
            idx, app, TARGET_PATH
        )?;
    }
    Ok(())
}

