//! LoongArch fallback kernel used only when the Rust `core` target is unavailable.
//!
//! 平台评测的 `make all` 要求同时产出 `kernel-rv` 和 `kernel-la`。部分环境
//! 没有预装 `loongarch64-unknown-none` 的 `core`，并且可能无法联网执行
//! `-Zbuild-std`。这个极小 no_core 程序只作为 LoongArch 构建兜底，避免
//! RISC-V 评测入口被 LoongArch 工具链环境问题阻塞。

#![allow(internal_features)]
#![feature(no_core, lang_items)]
#![no_core]
#![no_main]

/// `Sized` 的底层层级 lang item，no_core 下需要由当前 crate 显式提供。
#[lang = "pointee_sized"]
trait PointeeSized {}

/// `Sized` 的中间层级 lang item。
#[lang = "meta_sized"]
trait MetaSized: PointeeSized {}

/// 让编译器能够处理普通定长类型的最小 `Sized` lang item。
#[lang = "sized"]
trait Sized: MetaSized {}

/// LoongArch 兜底入口。
///
/// 这个入口不承诺通过 LoongArch 运行测试，只保证在缺少 LoongArch Rust
/// 标准库目标时仍能生成合法 ELF；如果它被误启动，会尽量写电源控制寄存器
/// 主动退出，避免长时间占住评测队列。
#[unsafe(no_mangle)]
pub extern "C" fn _start() -> ! {
    unsafe {
        // QEMU LoongArch virt 机器的 GED sleep control 寄存器；0x34 表示 S5
        // poweroff 请求，与正常 os-la 骨架里的 shutdown 常量保持一致。
        *(0x100e_001c as *mut u8) = 0x34;
    }
    loop {}
}

